// Validate token and parse pipeline event
const headers = $input.first().json.headers;
const body = $input.first().json.body;

// --- Token validation ---
const receivedToken = headers['x-gitlab-token'] || headers['X-Gitlab-Token'] || '';
const expectedToken = $env.GITLAB_WEBHOOK_SECRET;

if (!receivedToken || receivedToken !== expectedToken) {
  return [{ json: {
    valid: false,
    reason: 'Invalid or missing X-Gitlab-Token'
  }}];
}

const eventType = headers['x-gitlab-event'] || headers['X-Gitlab-Event'] || '';
if (eventType !== 'Pipeline Hook') {
  return [{ json: {
    valid: false,
    reason: `Unexpected event: ${eventType}`
  }}];
}

// --- Parse pipeline data ---
const pipeline = body.object_attributes || {};
const project = body.project || {};
const commit = body.commit || {};
const user = body.user || {};

// Build stage summary
const stages = (body.builds || []).map(b => ({
  name: b.name,
  stage: b.stage,
  status: b.status,
  duration: b.duration,
  failure_reason: b.failure_reason || null
}));

const failedStages = stages.filter(s => s.status === 'failed');

// Duration formatting
const durationSec = pipeline.duration || 0;
const durationFormatted = durationSec > 60
  ? `${Math.floor(durationSec / 60)}m ${durationSec % 60}s`
  : `${durationSec}s`;

return [{ json: {
  valid: true,
  pipeline_id: pipeline.id,
  pipeline_status: pipeline.status,
  pipeline_url: `${project.web_url}/-/pipelines/${pipeline.id}`,
  branch: pipeline.ref,
  project_name: project.name,
  project_path: project.path_with_namespace,
  project_id: project.id,
  project_url: project.web_url,
  commit_sha: commit.id || pipeline.sha,
  commit_short: (commit.id || pipeline.sha || '').substring(0, 8),
  commit_message: (commit.message || '').split('\n')[0],
  author: user.username || user.name || commit.author?.name || 'unknown',
  duration: durationFormatted,
  duration_seconds: durationSec,
  stages: stages,
  failed_stages: failedStages,
  failure_details: failedStages.map(s => `${s.stage}/${s.name}: ${s.failure_reason || 'unknown'}`).join('; '),
  timestamp: new Date().toISOString()
}}];

// Build CalVer tag: v{YYYY}.{MM}.{DD}.{N}
// N is determined after fetching existing tags from GitLab
const data = $json;
const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const datePrefix = `v${yyyy}.${mm}.${dd}`;

return [{ json: {
  ...data,
  calver_date_prefix: datePrefix,
  tag_search_pattern: `v${yyyy}.${mm}.${dd}`,
  gitlab_api_url: $env.GITLAB_API_URL || 'https://gitlab.com/api/v4'
}}];

// Calculate next CalVer version number
const data = $('Prepare CalVer Prefix').first().json;
const tags = $input.first().json;
const datePrefix = data.calver_date_prefix;

// Parse existing tags for today to find max N
let maxN = 0;
const tagList = Array.isArray(tags) ? tags : [];

for (const tag of tagList) {
  const tagName = tag.name || '';
  if (tagName.startsWith(datePrefix + '.')) {
    const nStr = tagName.replace(datePrefix + '.', '');
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > maxN) {
      maxN = n;
    }
  }
}

const nextN = maxN + 1;
const newTag = `${datePrefix}.${nextN}`;

return [{ json: {
  ...data,
  new_tag: newTag,
  tag_message: `Release ${newTag} - ${data.commit_message}`,
  existing_tags_today: tagList.length,
  previous_n: maxN
}}];

// Build rollback info for failed pipeline on main/staging
const data = $json;
const branch = data.branch;
const sha = data.commit_sha;
const shortSha = data.commit_short;

// Rollback command: revert the merge commit
const rollbackCmd = [
  `git checkout ${branch}`,
  `git pull origin ${branch}`,
  `git revert --no-edit -m 1 ${sha}`,
  `git push origin ${branch}`
].join(' && ');

// Alternative: force reset to previous commit
const resetCmd = `git push origin ${sha}~1:refs/heads/${branch} --force`;

return [{ json: {
  ...data,
  rollback_command: rollbackCmd,
  reset_command: resetCmd,
  rollback_description: `Revert commit ${shortSha} on ${branch}`,
  severity: 'critical'
}}];

// Auto-revert: create revert commit via GitLab API
const data = $json;
const apiUrl = $env.GITLAB_API_URL || 'https://gitlab.com/api/v4';

let result = { success: false, message: '' };

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: `${apiUrl}/projects/${data.project_id}/repository/commits`,
    headers: {
      'PRIVATE-TOKEN': $env.GITLAB_API_TOKEN,
      'Content-Type': 'application/json'
    },
    body: {
      branch: data.branch,
      commit_message: `Revert: auto-rollback after pipeline #${data.pipeline_id} failure\n\nReverts ${data.commit_short} (${data.commit_message})\n\nTriggered by n8n pipeline monitor.`,
      actions: []
    },
    resolveWithFullResponse: true,
    simple: false
  });

  // Note: empty actions array won't create a revert.
  // A proper revert needs the GitLab Revert API (available in GitLab 15.5+)
  // Using cherry-pick revert endpoint instead:
  const revertResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${apiUrl}/projects/${data.project_id}/repository/commits/${data.commit_sha}/revert`,
    headers: {
      'PRIVATE-TOKEN': $env.GITLAB_API_TOKEN,
      'Content-Type': 'application/json'
    },
    body: {
      branch: data.branch
    },
    resolveWithFullResponse: false,
    simple: false
  });

  result = {
    success: true,
    message: `Auto-reverted ${data.commit_short} on ${data.branch}`,
    revert_sha: revertResponse?.id || revertResponse?.short_id || 'unknown'
  };
} catch (err) {
  result = {
    success: false,
    message: `Auto-revert failed: ${err.message}. Manual rollback required: ${data.rollback_command}`
  };
}

return [{ json: { ...data, auto_revert: result } }];

// Return ignored response
return [{ json: {
  status: 'ignored',
  reason: $json.reason || 'Invalid webhook payload',
  timestamp: new Date().toISOString()
}}];

// Final response
return [{ json: {
  status: 'processed',
  pipeline_status: $json.pipeline_status || 'unknown',
  project: $json.project_name || 'unknown',
  branch: $json.branch || 'unknown',
  timestamp: new Date().toISOString()
}}];
